1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const DEDUCTIBLE = 100;
10	const CAP_MULTIPLIER = 2;
11	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
12	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
13	
14	type ItemTypeConfig = { basePremium: number; insuranceValue: number };
15	
16	const ITEM_TYPE_CONFIG: Record<string, ItemTypeConfig> = {
17	  sword: { basePremium: 100, insuranceValue: 1000 },
18	  amulet: { basePremium: 60, insuranceValue: 600 },
19	  staff: { basePremium: 80, insuranceValue: 800 },
20	  potion: { basePremium: 40, insuranceValue: 400 },
21	  rune: { basePremium: 25, insuranceValue: 250 },
22	  moonstone: { basePremium: 25, insuranceValue: 250 },
23	};
24	
25	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
26	type Customer = { yearsWithMHPCO: number };
27	type Damage = { itemType: string; amount: number };
28	type Incident = { cause: string; damages: Damage[] };
29	type QuoteStep = { op: "quote"; items: Item[] };
30	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
31	type Step = QuoteStep | ClaimStep;
32	type Scenario = { customer: Customer; steps: Step[] };
33	type QuoteResult = { premium: number };
34	type ClaimResult = { payout: number; remainingCap: number };
35	type StepResult = QuoteResult | ClaimResult;
36	
37	const sumBy = <T>(items: T[], valueOf: (item: T) => number): number =>
38	  items.reduce((sum, item) => sum + valueOf(item), 0);
39	
40	const basePremiumOf = (item: Item): number => ITEM_TYPE_CONFIG[item.type].basePremium;
41	
42	const enchantmentLevelOf = (item: Item): number => item.enchantment ?? 0;
43	
44	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
45	const BLOCK_SIZE = 3;
46	const BLOCK_BASE_PREMIUM = 60;
47	
48	const sumBasePremiums = (items: Item[]): number => sumBy(items, basePremiumOf);
49	
50	const componentGroupSubtotalOf = (group: Item[]): number =>
51	  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);
52	
53	const groupByType = (items: Item[]): Item[][] => {
54	  const groups = new Map<string, Item[]>();
55	  for (const item of items) {
56	    const group = groups.get(item.type);
57	    if (group) {
58	      group.push(item);
59	    } else {
60	      groups.set(item.type, [item]);
61	    }
62	  }
63	  return [...groups.values()];
64	};
65	
66	const componentSubtotalOf = (components: Item[]): number =>
67	  sumBy(groupByType(components), componentGroupSubtotalOf);
68	
69	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
70	
71	const policyBaseOf = (items: Item[]): number => {
72	  const components = items.filter(isComponent);
73	  const standaloneItems = items.filter((item) => !isComponent(item));
74	  return sumBasePremiums(standaloneItems) + componentSubtotalOf(components);
75	};
76	
77	const firstInsuranceSurchargeOf = (policyBase: number): number =>
78	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
79	
80	const cursedSurchargeOf = (item: Item): number =>
81	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
82	
83	const highEnchantmentSurchargeOf = (item: Item): number =>
84	  enchantmentLevelOf(item) >= HIGH_ENCHANTMENT_THRESHOLD
85	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
86	    : 0;
87	
88	const itemSurchargeOf = (item: Item): number =>
89	  cursedSurchargeOf(item) + highEnchantmentSurchargeOf(item);
90	
91	const itemSurchargesOf = (items: Item[]): number => sumBy(items, itemSurchargeOf);
92	
93	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
94	
95	const loyaltyDiscountOf = (policyBase: number, customer: Customer): number =>
96	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
97	
98	const followUpDiscountOf = (policyBase: number, isFollowUp: boolean): number =>
99	  isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
100	
101	const policySurchargesOf = (policyBase: number): number =>
102	  firstInsuranceSurchargeOf(policyBase);
103	
104	const policyDiscountsOf = (
105	  policyBase: number,
106	  customer: Customer,
107	  isFollowUp: boolean,
108	): number =>
109	  loyaltyDiscountOf(policyBase, customer) + followUpDiscountOf(policyBase, isFollowUp);
110	
111	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
112	  const policyBase = policyBaseOf(items);
113	  const surcharges = itemSurchargesOf(items) + policySurchargesOf(policyBase);
114	  const discounts = policyDiscountsOf(policyBase, customer, isFollowUp);
115	  const rawPremium = policyBase + surcharges - discounts + PROCESSING_FEE;
116	  return roundUpInMHPCOFavor(rawPremium);
117	};
118	
119	const isFollowUpContract = (stepIndex: number): boolean => stepIndex > 0;
120	
121	const insuranceValueOf = (item: Item): number => ITEM_TYPE_CONFIG[item.type].insuranceValue;
122	
123	const insuranceSumOf = (items: Item[]): number => sumBy(items, insuranceValueOf);
124	
125	const reimbursableDamageOf = (damage: Damage, insuredItem: Item): number =>
126	  enchantmentLevelOf(insuredItem) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
127	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
128	    : damage.amount;
129	
130	const damagePayoutOf = (damage: Damage, insuredItem: Item): number =>
131	  reimbursableDamageOf(damage, insuredItem) - DEDUCTIBLE;
132	
133	const findInsuredItem = (itemType: string, items: Item[]): Item =>
134	  items.find((item) => item.type === itemType) as Item;
135	
136	const incidentPayoutOf = (incident: Incident, policyItems: Item[]): number =>
137	  sumBy(incident.damages, (damage) =>
138	    damagePayoutOf(damage, findInsuredItem(damage.itemType, policyItems)),
139	  );
140	
141	const policyCapOf = (policyItems: Item[]): number =>
142	  insuranceSumOf(policyItems) * CAP_MULTIPLIER;
143	
144	const originatingQuoteOf = (claimStep: ClaimStep, scenario: Scenario): QuoteStep =>
145	  scenario.steps[claimStep.policy] as QuoteStep;
146	
147	const processClaim = (claimStep: ClaimStep, scenario: Scenario): ClaimResult => {
148	  const policyItems = originatingQuoteOf(claimStep, scenario).items;
149	  const payout = incidentPayoutOf(claimStep.incident, policyItems);
150	  const cap = policyCapOf(policyItems);
151	  return { payout, remainingCap: cap - payout };
152	};
153	
154	export const processScenario = (scenario: Scenario): { results: StepResult[] } => {
155	  const results: StepResult[] = scenario.steps.map((step, index) => {
156	    if (step.op === "quote") {
157	      return {
158	        premium: quotePremium(step.items, scenario.customer, isFollowUpContract(index)),
159	      };
160	    }
161	    return processClaim(step, scenario);
162	  });
163	  return { results };
164	};
