const processQuote = (
  quoteStep: QuoteStep,
  scenario: Scenario,
  stepIndex: number,
): QuoteResult => ({
  premium: quotePremium(quoteStep.items, scenario.customer, isFollowUpContract(stepIndex)),
});

const processClaim = (claimStep: ClaimStep, scenario: Scenario): ClaimResult => {
  const policyItems = originatingQuoteOf(claimStep, scenario).items;
  const payout = incidentPayoutOf(claimStep.incident, policyItems);
  const cap = policyCapOf(policyItems);
  return { payout, remainingCap: cap - payout };
};

const processStep = (step: Step, scenario: Scenario, stepIndex: number): StepResult =>
  step.op === "quote" ? processQuote(step, scenario, stepIndex) : processClaim(step, scenario);

export const processScenario = (scenario: Scenario): { results: StepResult[] } => ({
  results: scenario.steps.map((step, index) => processStep(step, scenario, index)),
});
